1	/**
2	 * Scorer — score card display and run comparison drawer.
3	 *
4	 * Depends on: RunStore, Metrics (inline-ported for browser use)
5	 * Does NOT require Node.js modules; duplicates minimal logic for browser.
6	 */
7	
8	var Scorer = (function() {
9	
10	    // ── Minimal in-browser RunStore ────────────────────────────────────
11	    var STORAGE_KEY = 'pf_runs';
12	    var _counter = 0;
13	
14	    function _read() {
15	        try {
16	            var raw = localStorage.getItem(STORAGE_KEY);
17	            return raw ? JSON.parse(raw) : [];
18	        } catch (e) { return []; }
19	    }
20	
21	    function _write(runs) {
22	        try { localStorage.setItem(STORAGE_KEY, JSON.stringify(runs)); } catch (e) {}
23	    }
24	
25	    function saveRun(record) {
26	        var runs = _read();
27	        var saved = {};
28	        for (var k in record) {
29	            if (record.hasOwnProperty(k)) saved[k] = record[k];
30	        }
31	        saved.id = String(Date.now()) + '_' + (++_counter);
32	        runs.push(saved);
33	        _write(runs);
34	        return saved;
35	    }
36	
37	    function loadRuns() { return _read(); }
38	
39	    function clearRuns() {
40	        try { localStorage.removeItem(STORAGE_KEY); } catch (e) {}
41	    }
42	
43	    function deleteRun(id) {
44	        _write(_read().filter(function(r) { return r.id !== id; }));
45	    }
46	
47	    // ── Metrics ────────────────────────────────────────────────────────
48	    function pathLength(path) {
49	        var len = 0;
50	        for (var i = 1; i < path.length; i++) {
51	            var dx = path[i][0] - path[i-1][0];
52	            var dy = path[i][1] - path[i-1][1];
53	            len += Math.sqrt(dx*dx + dy*dy);
54	        }
55	        return len;
56	    }
57	
58	    function captureRun(algorithm, path, timeMs, nodesExplored) {
59	        return {
60	            algorithm:     algorithm,
61	            pathLength:    Math.round(pathLength(path) * 100) / 100,
62	            nodesExplored: nodesExplored,
63	            timeMs:        parseFloat(timeMs),
64	            timestamp:     Date.now()
65	        };
66	    }
67	
68	    // ── DOM helpers ────────────────────────────────────────────────────
69	    function fmt(n) {
70	        return (n === undefined || n === null) ? '—' : String(n);
71	    }
72	
73	    function fmtTime(ms) {
74	        return parseFloat(ms).toFixed(4) + ' ms';
75	    }
76	
77	    function fmtDate(ts) {
78	        var d = new Date(ts);
79	        return d.toLocaleTimeString();
80	    }
81	
82	    // ── Score card ─────────────────────────────────────────────────────
83	    function showScoreCard(record) {
84	        var $card = $('#score_card');
85	        $card.find('.sc-algorithm').text(record.algorithm);
86	        $card.find('.sc-path-length').text(fmt(record.pathLength));
87	        $card.find('.sc-nodes').text(fmt(record.nodesExplored));
88	        $card.find('.sc-time').text(fmtTime(record.timeMs));
89	        $card.find('.sc-save-btn').off('click').on('click', function() {
90	            var saved = saveRun(record);
91	            refreshDrawer();
92	            $card.find('.sc-saved-msg').text('Saved #' + saved.id.split('_')[1]).show();
93	            setTimeout(function() { $card.find('.sc-saved-msg').hide(); }, 2000);
94	        });
95	        $card.show();
96	    }
97	
98	    // ── Comparison drawer ──────────────────────────────────────────────
99	    function renderRunRow(run) {
100	        return $('<tr>')
101	            .append($('<td>').text(fmtDate(run.timestamp)))
102	            .append($('<td>').text(run.algorithm))
103	            .append($('<td>').text(fmt(run.pathLength)))
104	            .append($('<td>').text(fmt(run.nodesExplored)))
